import React from 'react';
import { Outlet, Route, Routes } from 'react-router-dom';
import './App.css';
import Footer from './components/Footer';
import Nav from './components/Nav';
import MainPage from './pages/MainPage';
import DetailPage from './pages/DetailPage';
import SearchPage from './pages/SearchPage';
import SigninPage from './pages/Signin/Signin'; // 정확한 경로
import HomePopular from './views/Home/HomePopular/HomePopular';
import HomeSearch from './views/Search/HomeSearch';

// ** Home 및 HomeWishlist 컴포넌트 import 추가 **
import Home from './views/Home/Home'; // 정확한 경로
import HomeWishlist from './views/Home/HomeWishlist/HomeWishlist.js'; // 정확한 경로

const Layout = () => {
  return (
    <div>
      <Nav />
      <Outlet />
      <Footer />
    </div>
  );
};

function App() {
  return (
    <div className="App">
      <Routes>
        <Route path="/" element={<Layout />}>
          <Route index element={<MainPage />} />
          <Route path=":movieId" element={<DetailPage />} />
          <Route path="search" element={<SearchPage />} />
        </Route>

        {/* Home.js로 중첩 라우팅 */}
        <Route path="/home" element={<Home />}>
          <Route path="popular" element={<HomePopular />} />
          <Route path="search" element={<HomeSearch />} />
          <Route path="wishlist" element={<HomeWishlist />} />
        </Route>

        <Route path="/signin" element={<SigninPage />} /> {/* 로그인/회원가입 */}
      </Routes>
    </div>
  );
}

export default App;
